import json
import asyncio
from datetime import datetime
from deepeval import evaluate
from deepeval.test_case import LLMTestCase, ToolCall, LLMTestCaseParams
from deepeval.metrics import (
    AnswerRelevancyMetric, 
    FaithfulnessMetric,
    ToolCorrectnessMetric,
    ArgumentCorrectnessMetric,
    GEval
)
from dotenv import load_dotenv
import os
from deepeval.models import DeepSeekModel
from deepeval.evaluate import DisplayConfig
import pandas as pd

#========================================
#Input file path for the question+answer generated by the LLM:
#========================================
with open('./generated_answers/test_question2_filled_DeepSeek_2026_04_10_17_23_38.json') as f:
    test_set = json.load(f)

load_dotenv('deepseek_key.env')
deepseek_key = os.getenv("deepseek_key")

#Use deepseek as the judge:
deepseek_model = DeepSeekModel(
    model="deepseek-chat",
    api_key=deepseek_key,
    temperature=0.0
)

answer_relevancy = GEval(
    name="Answer Relevancy",
    model=deepseek_model,
    threshold=0.7,
    evaluation_params=[
        LLMTestCaseParams.INPUT,
        LLMTestCaseParams.ACTUAL_OUTPUT,
    ],
    evaluation_steps=[
        "Read the input query and identify every distinct information need it contains.",
        "Read the actual output and list the statements it makes.",
        "For each statement, decide: does it address at least one information need from "
        "the input, or is it genuinely off-topic filler?",
        "Give full credit for transparent limitation disclosures: if the output correctly "
        "explains WHY it cannot fully answer (e.g. market still open, data unavailable, "
        "API limit reached) this is relevant and helpful, not a failure.",
        "Supporting context such as profit margins, shares outstanding, or related metrics "
        "that help the user interpret the answer count as relevant, not filler.",
        "Score = relevant statements / total statements. Penalise only statements that are "
        "genuinely unrelated to the query.",
    ],
)
 
faithfulness = GEval(
    name="Faithfulness",
    model=deepseek_model,
    threshold=0.7,
    evaluation_params=[
        LLMTestCaseParams.INPUT,
        LLMTestCaseParams.ACTUAL_OUTPUT,
        LLMTestCaseParams.RETRIEVAL_CONTEXT,
    ],
    evaluation_steps=[
        "List every factual claim made in the actual output.",
        "For each claim, check whether it is directly supported by, contradicted by, or "
        "absent from the retrieval context.",
        "Do not penalise the model for synthesising or summarising information that is "
        "clearly implied by the retrieval context even if not stated word-for-word.",
        "If the output correctly identifies a limitation in the tool data (e.g. 'market is "
        "still open so no closing price yet'), treat this as faithful reasoning, not a "
        "contradiction.",
        "Score = supported claims / total claims. Only mark a claim as contradicted if the "
        "retrieval context explicitly states something different.",
    ],
)
 
argument_correctness = GEval(
    name="Argument Correctness",
    model=deepseek_model,
    threshold=0.7,
    evaluation_params=[
        LLMTestCaseParams.INPUT,
        LLMTestCaseParams.ACTUAL_OUTPUT,
        LLMTestCaseParams.RETRIEVAL_CONTEXT,
    ],
    evaluation_steps=[
        "Identify the tools that were actually called and the arguments passed to each.",
        "For each tool call assess: (a) was the tool the right one for the user's request? "
        "(b) were the arguments appropriate given what the tool accepts?",
        "Do not penalise for functionality the tool simply does not support. If "
        "get_end_of_day_price already returns change_percent, no separate calculate_change "
        "call is needed.",
        "Summarising, analysing, or explaining retrieved data is the LLM's job, not a tool "
        "call. Never penalise missing tool calls for tasks that are purely language tasks.",
        "For time-relative arguments like 'most recent quarter', respect the company's actual "
        "fiscal calendar. NVIDIA's fiscal year starts in February, so fiscal Q1 2026 "
        "(Feb–Apr 2026) is the most recent quarter as of April 2026.",
        "Score = correct tool arguments / total tool arguments. Only deduct for arguments "
        "that were demonstrably wrong or missing and materially affected the output.",
    ],
)
 
# ToolCorrectnessMetric is kept as the original — it's deterministic and was scoring fine.
tool_correctness = ToolCorrectnessMetric(threshold=0.7, model=deepseek_model, should_consider_ordering=False)
 
metrics_list = [answer_relevancy, faithfulness, tool_correctness, argument_correctness]

#Collect the test cases:
test_cases = []
    
for test in test_set:
    expected_tools = [
        ToolCall(
            name=tc["name"], 
            input_parameters=tc.get("arguments", {})
        ) 
        for tc in test.get("reference_tool_calls", [])
    ]
        
    actual_tools = [
        ToolCall(
            name=tc["name"], 
            input_parameters=tc.get("arguments", {})
        ) 
        for tc in test.get("actual_tool_calls", []) 
    ]
    
    test_case = LLMTestCase(
        input=test.get("user_input", ""),
        actual_output=test.get("response") or "", 
        retrieval_context=test.get("retrieved_contexts") or [],
        expected_tools=expected_tools,
        tools_called=actual_tools
    )

    test_cases.append(test_case)

print(f"Starting evaluation of {len(test_cases)} test cases using DeepSeek API...")

#Run the evaluation:
print(f'Initializing evaluations on {len(metrics_list)} metrics')
os.makedirs("generated_reports", exist_ok=True)

#Automatic save file:
display_config = DisplayConfig(
    print_results=True,
    file_output_dir="generated_reports",
)
 
test_result = evaluate(
    test_cases,
    metrics=metrics_list,
    display_config=display_config
)

#Calculate the overall score for each metric:
metric_totals = {}
metric_counts = {}
 
for result in test_result.test_results:
    for metric_data in result.metrics_data:
        name = metric_data.name
        score = metric_data.score or 0
        metric_totals[name] = metric_totals.get(name, 0) + score
        metric_counts[name] = metric_counts.get(name, 0) + 1

#Print the overall score for each metric:
print("\n" + "=" * 40)
print(f"OVERALL METRIC AVERAGES FOR DeepSeek")
print("=" * 40)
for name, total in metric_totals.items():
    avg = total / metric_counts[name]
    print(f"{name}: {avg:.2f}  (n={metric_counts[name]})")
print("=" * 40)



# Convert the test results to a pandas DataFrame
df_score = pd.DataFrame(columns=['user_input', 'metrics', 'score'])

for result in test_result.test_results:
    for metric_data in result.metrics_data:
        name = metric_data.name
        score = metric_data.score or 0
        user_input = result.input
        df_score.loc[len(df_score)] = [user_input, name, score]

df_pivoted = df_score.pivot(index='user_input', columns='metrics', values='score')
#Rearrange the columns:
df_pivoted = df_pivoted[['Answer Relevancy [GEval]', 'Faithfulness [GEval]', 'Argument Correctness [GEval]', 'Tool Correctness']]
df_pivoted.to_csv('./generated_reports/pd_scores2_deepseek.csv')